const BUILDING_TYPES = {
  base: { maxHp: 600, cost: { gold: 0 }, buildTimeMs: 0, canTrain: ['worker', 'soldier'] },
  barracks: { maxHp: 450, cost: { gold: 200 }, buildTimeMs: 2000, canTrain: ['soldier'] },
  turret: { maxHp: 300, cost: { gold: 150 }, buildTimeMs: 1600, attack: { range: 10, damage: 12, cooldownMs: 700 } },
};

const SPAWN = {
  startGold: process.env.START_GOLD ? Number(process.env.START_GOLD) : 500,
  baseRadius: 6,
};

function clamp(v, a, b) { return v < a ? a : v > b ? b : v; }
function dist2(ax, ay, bx, by) { const dx = ax - bx, dy = ay - by; return dx * dx + dy * dy; }
